@Test
public void shouldBeSerializableWhenOnlySerializableSet() throws Exception {
    //when
    IMethods mock = mock(IMethods.class, withSettings().serializable());

    //then
    serializeAndBack(mock);
}

@Test
public void shouldNotBeSerializableWhenOnlyExtraInterfacesSet() throws Exception {
    //when
    IMethods mock = mock(IMethods.class, withSettings().extraInterfaces(List.class));

    //then
    assertFalse(mock instanceof java.io.Serializable);
}

@Test
public void shouldHaveMultipleExtraInterfacesAndBeSerializable() throws Exception {
    //when
    IMethods mock = mock(IMethods.class, withSettings().serializable().extraInterfaces(List.class, Cloneable.class));

    //then
    assertTrue(mock instanceof java.io.Serializable);
    assertTrue(mock instanceof List);
    assertTrue(mock instanceof Cloneable);
    serializeAndBack(mock);
}
